"""Контроллер модалок приложения: GUIModalsController(modal_layer)."""from __future__ import annotationsimport tkinter as tkfrom src.gui.modals.confirm_modal import ConfirmModalfrom src.gui.modals.info_modal import InfoModalfrom src.gui.modals.input_modal import InputModalclass GUIModalsController:    """Контроллер модалок: один экземпляр каждого типа. Создаётся как GUIModalsController(modal_layer)."""    def __init__(self, modal_layer: tk.Misc) -> None:        self._confirm = ConfirmModal(modal_layer, confirm_text="ОК", cancel_text="Отмена")        self._info = InfoModal(modal_layer)        self._input = InputModal(modal_layer, submit_text="Создать", cancel_text="Отмена")    def show_info(        self,        title: str,        message: str,        *,        errors: list[str] | None = None,    ) -> None:        self._info.show_info(title, message, errors=errors)    def show_confirm(        self,        title: str,        message: str,        on_confirm,        *,        confirm_text: str | None = None,        cancel_text: str | None = None,    ) -> None:        self._confirm.show_confirm(            title, message, on_confirm,            confirm_text=confirm_text,            cancel_text=cancel_text,        )    def show_input(        self,        title: str,        prompt: str,        on_submit,        default: str = "",        *,        submit_text: str | None = None,        cancel_text: str | None = None,    ) -> None:        self._input.show_input(            title, prompt, on_submit, default,            submit_text=submit_text,            cancel_text=cancel_text,        )